async function run() {
  console.log(`Importando ${products.length} productos...`);
  let inserted = 0;
  let updated = 0;

  for (const p of products) {
    const existing = await prisma.product.findUnique({ where: { code: p.code } });
    if (existing) {
      await prisma.product.update({ where: { code: p.code }, data: p });
      updated++;
    } else {
      await prisma.product.create({ data: p });
      inserted++;
    }
  }

  console.log(`Listo: ${inserted} nuevos, ${updated} actualizados.`);
  await prisma.$disconnect();
}

run().catch((e) => {
  console.error(e);
  process.exit(1);
});
